const b = $json.body || {};

// --------------------
// 1) Sectors (multi-select sectors[x])
// --------------------
const sectors = Object.keys(b)
  .filter(k => k.startsWith('sectors['))
  .sort((a, c) => {
    const ai = parseInt((a.match(/\[(\d+)\]/) || [])[1] || '0', 10);
    const ci = parseInt((c.match(/\[(\d+)\]/) || [])[1] || '0', 10);
    return ai - ci;
  })
  .map(k => b[k])
  .filter(Boolean);

// --------------------
// 2) Date handling (Avada sends d/m/Y)
// --------------------
const fromDateStr = b.date || ""; // e.g. "01/01/2026"
let fromIso = "";
let daysBack = null;

if (fromDateStr) {
  const [dd, mm, yyyy] = fromDateStr.split("/").map(s => s.trim());
  if (dd && mm && yyyy) {
    fromIso = `${yyyy}-${mm.padStart(2, "0")}-${dd.padStart(2, "0")}`;

    const today = new Date();
    const todayUtcMidnight = Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate());
    const fromUtcMidnight = Date.UTC(parseInt(yyyy, 10), parseInt(mm, 10) - 1, parseInt(dd, 10));
    daysBack = Math.max(0, Math.floor((todayUtcMidnight - fromUtcMidnight) / (1000 * 60 * 60 * 24)));
  }
}

// --------------------
// 3) Sector -> website field mapping (must match your Avada field names)
// --------------------
const sectorToWebsiteFieldBase = {
  "Healthcare": "website_for_healthcare",
  "Food & Catering": "website_for_food_and_catering",
  "Retail": "website_for_retail",
  "Manufacturing": "website_for_manufacturing",
  "Logistics": "website_for_logistics",
  "Facilities Management": "website_for_facilities_management",
  "Other": "website_for_other",
};

// Helper: get all checkbox values for a base field like website_for_healthcare[x]
function collectCheckboxGroup(baseName) {
  return Object.keys(b)
    .filter(k => k.startsWith(`${baseName}[`))
    .sort((a, c) => {
      const ai = parseInt((a.match(/\[(\d+)\]/) || [])[1] || '0', 10);
      const ci = parseInt((c.match(/\[(\d+)\]/) || [])[1] || '0', 10);
      return ai - ci;
    })
    .map(k => b[k])
    .filter(Boolean);
}

// --------------------
// 4) Only keep websites for SELECTED sectors
//    (and only those still ticked)
// --------------------
const websites_by_sector = {};
let selected_websites = [];

for (const sector of sectors) {
  const base = sectorToWebsiteFieldBase[sector];
  if (!base) continue;

  const sites = collectCheckboxGroup(base);
  websites_by_sector[sector] = sites;
  selected_websites.push(...sites);
}

// De-dupe
selected_websites = [...new Set(selected_websites)];

// --------------------
// 5) Output tidy object
// --------------------
return [
  {
    json: {
      form_id: b.form_id,
      submitted_at: b.time,
      source_url: b.source_url,
      wp_user_id: b.user_id,

      name: b.name,
      company: b.company_name,
      email: b.email_address,
      topic: b.what_would_you_like_us_to_research,

      sectors,

      from_date: fromDateStr,
      from_iso: fromIso,
      days_back: daysBack,

      // new outputs
      websites_by_sector,
      selected_websites,

      ip: b.ip,
    }
  }
];

